"""Configuration constants for the Library Management System.This module eliminates magic numbers and centralizes all adjustablebusiness rules."""# ============================================================================# Borrowing Rules# ============================================================================MAX_BORROW_LIMIT = 5              # Maximum books a member can borrow at onceDEFAULT_LOAN_PERIOD_DAYS = 14     # Standard loan duration in daysREFERENCE_BOOK_LOAN_PERIOD_DAYS = 2  # Shorter loan for reference books# ============================================================================# Fine Configuration (Table-Driven)# ============================================================================DAILY_FINE_RATE_FIRST_WEEK = 0.50DAILY_FINE_RATE_AFTER_WEEK = 1.00DAILY_FINE_RATE_EXTENDED = 2.00MAXIMUM_FINE_AMOUNT = 100.00MAX_FINE_BEFORE_SUSPENSION = 50.00# Fine tiers: (min_days, max_days, rate_per_day)FINE_TIERS = [    (1, 7, DAILY_FINE_RATE_FIRST_WEEK),    (8, 30, DAILY_FINE_RATE_AFTER_WEEK),    (31, float('inf'), DAILY_FINE_RATE_EXTENDED),  # Open-ended tier]# ============================================================================# Reservation Rules# ============================================================================RESERVATION_EXPIRY_DAYS = 7MAX_RESERVATIONS_PER_MEMBER = 3